mapper.select:
select id, celebrity_private_id, private_account, year, month, goods_num, goods_price, settlement_price, reality_settlement_price, settlement_status, remark from store_celebrity_settlement
and private_account like '%${storeCelebritySettlementModel.privateAccount}%'
and year = #{storeCelebritySettlementModel.year}
and month = #{storeCelebritySettlementModel.month}
and settlement_status = #{storeCelebritySettlementModel.settlementStatus}
group by id, celebrity_private_id ,private_account,year,month,goods_num,goods_price,settlement_price,reality_settlement_price, settlement_status,remark
ORDER BY year ,month desc
